// Collect all upstream data and pass it forward as a single merged payload
const alarms = $('Fetch Triggered Alarms').all().map(i => i.json);
const submissions = $('Fetch Today\'s Submissions').all().map(i => i.json);
const groups = $('Fetch Group JID Map').all().map(i => i.json);

return alarms.map(alarm => ({
  ...alarm,
  _submissions: submissions,
  _groups: groups
}));

const IST_offset = 5.5 * 60 * 60 * 1000;
const now = new Date(new Date().getTime() + IST_offset);

let reminder = { ...$json };
const submissions = reminder._submissions || [];
const groups = reminder._groups || [];
const phoneStr = String(reminder.person_phone || '').trim();
let triggerTime = new Date(new Date(reminder.trigger_time).getTime() + IST_offset);

let assignedReports = reminder.report_types
  ? reminder.report_types.split(',').map(s => s.trim()).filter(Boolean)
  : [];
let missing_list = [];

let groupName = null;
if (reminder.whatsapp_group_id) {
    let gMatch = groups.find(g => g.whatsapp_group_id === reminder.whatsapp_group_id);
    if (gMatch) groupName = gMatch.name;
}

for (let report of assignedReports) {
    let submitted = false;
    let r_lower = report.toLowerCase();
    let categories = [];
    if (r_lower.includes("production")) {
        categories = ['production', 'egg_collection', 'egg_collection_1', 'egg_collection_2', 'egg'];
    } else if (r_lower.includes("feed")) {
        categories = ['feed'];
    } else if (r_lower.includes("expense")) {
        categories = ['expense', 'purchase'];
    } else if (r_lower.includes("sale")) {
        categories = ['sales'];
    } else if (r_lower.includes("profit") || r_lower.includes("p&l") || r_lower.includes("p and l")) {
        categories = ['sales', 'expense', 'purchase'];
    }

    for (let sub of submissions) {
        let matchSender = sub.sender && sub.sender.includes(phoneStr);
        let matchGroup = groupName && sub.group_name === groupName;
        if (matchSender || matchGroup) {
            if (categories.length > 0) {
                if (categories.includes(sub.category)) { submitted = true; break; }
            } else {
                let notes_lower = (sub.notes || '').toLowerCase();
                if (notes_lower.includes(r_lower)) { submitted = true; break; }
            }
        }
    }
    if (!submitted) missing_list.push(report);
}

let reports_missing = missing_list.length > 0;
let nextTime = new Date(triggerTime.getTime());
let newStatus = 'pending';

if (reports_missing) {
    if (reminder.repeat_interval && reminder.repeat_interval !== 'none') {
        let minutes = 0;
        if (reminder.repeat_interval === '5m') minutes = 5;
        else if (reminder.repeat_interval === '10m') minutes = 10;
        else if (reminder.repeat_interval === '15m') minutes = 15;
        else if (reminder.repeat_interval === '30m') minutes = 30;
        else if (reminder.repeat_interval === '1h') minutes = 60;

        if (minutes > 0) {
            let hour = now.getUTCHours();
            if (hour >= 6 && hour < 23) {
                nextTime = new Date(now.getTime() + minutes * 60 * 1000);
            } else {
                nextTime = getNextOccurrence(triggerTime, reminder.frequency);
            }
        }
    } else {
        nextTime = getNextOccurrence(triggerTime, reminder.frequency);
    }
} else {
    nextTime = getNextOccurrence(triggerTime, reminder.frequency);
}

let nextUTC = new Date(nextTime.getTime() - IST_offset);
reminder.next_trigger_time = nextUTC.toISOString().slice(0, 19).replace('T', ' ');
reminder.new_status = newStatus;
reminder.reports_missing = reports_missing;
reminder.missing_list = missing_list;
reminder.missing_reports = missing_list.join(', ');
reminder.target_whatsapp_id = phoneStr.length === 10 ? `91${phoneStr}@c.us` : `${phoneStr}@c.us`;
reminder.private_message = `⏰ *Sunfra Farm Reminder*\n\nDear *${reminder.person_name}*, please submit the following report(s) today:\n*${reminder.missing_reports}*\n\nNotes: ${reminder.task_notes}`;
reminder.group_message = `⏰ *Sunfra Farm Reminder*\n\n@${reminder.person_name}, please submit the following report(s) today:\n*${reminder.missing_reports}*\n\nNotes: ${reminder.task_notes}`;

return reminder;

function getNextOccurrence(baseTime, frequency) {
    let next = new Date(baseTime.getTime());
    let now2 = new Date(new Date().getTime() + 5.5 * 60 * 60 * 1000);
    do {
        if (frequency === 'weekly') next.setDate(next.getDate() + 7);
        else if (frequency === 'monthly') next.setMonth(next.getMonth() + 1);
        else if (frequency === 'yearly') next.setFullYear(next.getFullYear() + 1);
        else next.setDate(next.getDate() + 1);
    } while (next <= now2);
    return next;
}
